1	"use client";
2	
3	import { useEffect, useRef, useState, useMemo } from "react";
4	import { useRouter, usePathname, useSearchParams } from "next/navigation";
5	import { useTheme } from "next-themes";
6	import { cn } from "@/lib/cn";
7	import { useMux } from "@/hooks/useMux";
8	
9	// Import xterm CSS (must be imported in client component)
10	import "@xterm/xterm/css/xterm.css";
11	
12	// Dynamically import xterm types for TypeScript
13	import type { ITheme, Terminal as TerminalType } from "@xterm/xterm";
14	import type { FitAddon as FitAddonType } from "@xterm/addon-fit";
15	
16	interface DirectTerminalProps {
17	  sessionId: string;
18	  startFullscreen?: boolean;
19	  /** Visual variant. Orchestrator keeps the same design-system blue accent as the rest of the app. */
20	  variant?: "agent" | "orchestrator";
21	  appearance?: "theme" | "dark";
22	  /** CSS height for the terminal container in normal (non-fullscreen) mode.
23	   *  Defaults to "max(440px, calc(100vh - 440px))". */
24	  height?: string;
25	  isOpenCodeSession?: boolean;
26	  reloadCommand?: string;
27	  chromeless?: boolean;
28	}
29	
30	type TerminalVariant = "agent" | "orchestrator";
31	
32	
33	export function buildTerminalThemes(variant: TerminalVariant): { dark: ITheme; light: ITheme } {
34	  const agentAccent = {
35	    cursor: "#5b7ef8",
36	    selDark: "rgba(91, 126, 248, 0.30)",
37	    selLight: "rgba(91, 126, 248, 0.25)",
38	  };
39	  const orchAccent = agentAccent;
40	  const accent = variant === "orchestrator" ? orchAccent : agentAccent;
41	
42	  const dark: ITheme = {
43	    background: "#0a0a0f",
44	    foreground: "#d4d4d8",
45	    cursor: accent.cursor,
46	    cursorAccent: "#0a0a0f",
47	    selectionBackground: accent.selDark,
48	    selectionInactiveBackground: "rgba(128, 128, 128, 0.2)",
49	    // ANSI colors — slightly warmer than pure defaults
50	    black: "#1a1a24",
51	    red: "#ef4444",
52	    green: "#22c55e",
53	    yellow: "#f59e0b",
54	    blue: "#5b7ef8",
55	    magenta: "#a371f7",
56	    cyan: "#22d3ee",
57	    white: "#d4d4d8",
58	    brightBlack: "#50506a",
59	    brightRed: "#f87171",
60	    brightGreen: "#4ade80",
61	    brightYellow: "#fbbf24",
62	    brightBlue: "#7b9cfb",
63	    brightMagenta: "#c084fc",
64	    brightCyan: "#67e8f9",
65	    brightWhite: "#eeeef5",
66	  };
67	
68	  const light: ITheme = {
69	    background: "#fafafa",
70	    foreground: "#24292f",
71	    cursor: accent.cursor,
72	    cursorAccent: "#fafafa",
73	    selectionBackground: accent.selLight,
74	    selectionInactiveBackground: "rgba(128, 128, 128, 0.15)",
75	    // ANSI colors — darkened for legibility on #fafafa terminal background
76	    black: "#24292f",
77	    red: "#b42318",
78	    green: "#1f7a3d",
79	    yellow: "#8a5a00",
80	    blue: "#175cd3",
81	    magenta: "#8e24aa",
82	    cyan: "#0b7285",
83	    white: "#4b5563",
84	    brightBlack: "#374151",
85	    brightRed: "#912018",
86	    brightGreen: "#176639",
87	    brightYellow: "#6f4a00",
88	    brightBlue: "#1d4ed8",
89	    brightMagenta: "#7b1fa2",
90	    brightCyan: "#155e75",
91	    brightWhite: "#374151",
92	  };
93	
94	  return { dark, light };
95	}
96	
97	/**
98	 * Direct xterm.js terminal with native WebSocket connection.
99	 * Implements Extended Device Attributes (XDA) handler to enable
100	 * tmux clipboard support (OSC 52) without requiring iTerm2 attachment.
101	 *
102	 * Based on DeepWiki analysis:
103	 * - tmux queries for XDA (CSI > q / XTVERSION) to detect terminal type
104	 * - When tmux sees "XTerm(" in response, it enables TTYC_MS (clipboard)
105	 * - xterm.js doesn't implement XDA by default, so we register custom handler
106	 */
107	export function DirectTerminal({
108	  sessionId,
109	  startFullscreen = false,
110	  variant = "agent",
111	  appearance = "theme",
112	  height = "max(440px, calc(100dvh - 440px))",
113	  isOpenCodeSession = false,
114	  reloadCommand,
115	  chromeless = false,
116	}: DirectTerminalProps) {
117	  const router = useRouter();
118	  const pathname = usePathname();
119	  const searchParams = useSearchParams();
120	  const { resolvedTheme } = useTheme();
121	  const terminalThemes = useMemo(() => buildTerminalThemes(variant), [variant]);
122	  const { subscribeTerminal, writeTerminal, resizeTerminal: resizeTerminalMux, openTerminal, closeTerminal, status: muxStatus } = useMux();
123	
124	  const terminalRef = useRef<HTMLDivElement>(null);
125	  const terminalInstance = useRef<TerminalType | null>(null);
126	  const fitAddon = useRef<FitAddonType | null>(null);
127	  const muxStatusRef = useRef(muxStatus);
128	  muxStatusRef.current = muxStatus;
129	  const [fullscreen, setFullscreen] = useState(startFullscreen);
130	  const [error, setError] = useState<string | null>(null);
131	  const [reloading, setReloading] = useState(false);
132	  const [reloadError, setReloadError] = useState<string | null>(null);
133	
134	  // Update URL when fullscreen changes
135	  useEffect(() => {
136	    const params = new URLSearchParams(searchParams.toString());
137	
138	    if (fullscreen) {
139	      params.set("fullscreen", "true");
140	    } else {
141	      params.delete("fullscreen");
142	    }
143	
144	    const newUrl = params.toString() ? `${pathname}?${params.toString()}` : pathname;
145	    router.replace(newUrl, { scroll: false });
146	  }, [fullscreen, pathname, router, searchParams]);
147	
148	  async function handleReload(): Promise<void> {
149	    if (!isOpenCodeSession || reloading) return;
150	    setReloadError(null);
151	    setReloading(true);
152	    try {
153	      let commandToSend = reloadCommand;
154	
155	      if (!commandToSend) {
156	        const remapRes = await fetch(`/api/sessions/${encodeURIComponent(sessionId)}/remap`, {
157	          method: "POST",
158	        });
159	        if (!remapRes.ok) {
160	          throw new Error(`Failed to remap OpenCode session: ${remapRes.status}`);
161	        }
162	        const remapData = (await remapRes.json()) as { opencodeSessionId?: unknown };
163	        if (
164	          typeof remapData.opencodeSessionId !== "string" ||
165	          remapData.opencodeSessionId.length === 0
166	        ) {
167	          throw new Error("Missing OpenCode session id after remap");
168	        }
169	        commandToSend = `/exit\nopencode --session ${remapData.opencodeSessionId}\n`;
170	      }
171	
172	      const sendRes = await fetch(`/api/sessions/${encodeURIComponent(sessionId)}/send`, {
173	        method: "POST",
174	        headers: { "Content-Type": "application/json" },
175	        body: JSON.stringify({ message: commandToSend }),
176	      });
177	      if (!sendRes.ok) {
178	        throw new Error(`Failed to send reload command: ${sendRes.status}`);
179	      }
180	    } catch (err) {
181	      setReloadError(err instanceof Error ? err.message : "Failed to reload OpenCode session");
182	    } finally {
183	      setReloading(false);
184	    }
185	  }
186	
187	  useEffect(() => {
188	    if (!terminalRef.current) return;
189	
190	    // Dynamically import xterm.js to avoid SSR issues
191	    let mounted = true;
192	    let cleanup: (() => void) | null = null;
193	    let inputDisposable: { dispose(): void } | null = null;
194	    let unsubscribe: (() => void) | null = null;
195	
196	    Promise.all([
197	      import("@xterm/xterm").then((mod) => mod.Terminal),
198	      import("@xterm/addon-fit").then((mod) => mod.FitAddon),
199	      import("@xterm/addon-web-links").then((mod) => mod.WebLinksAddon),
200	      document.fonts.ready,
201	    ])
202	      .then(([Terminal, FitAddon, WebLinksAddon]) => {
203	        if (!mounted || !terminalRef.current) return;
204	
205	        const isDark = appearance === "dark" || resolvedTheme !== "light";
206	        const activeTheme = isDark ? terminalThemes.dark : terminalThemes.light;
207	
208	        // Initialize xterm.js Terminal
209	        const terminal = new Terminal({
210	          cursorBlink: true,
211	          fontSize: 13,
212	          fontFamily:
213	            'var(--font-jetbrains-mono), "JetBrains Mono", "SF Mono", Menlo, Monaco, "Courier New", monospace',
214	          theme: activeTheme,
215	          // Light mode needs an explicit contrast floor because agent UIs often emit
216	          // dim/faint ANSI sequences that become unreadable on a near-white background.
217	          minimumContrastRatio: isDark ? 1 : 7,
218	          scrollback: 10000,
219	          allowProposedApi: true,
220	          fastScrollModifier: "alt",
221	          fastScrollSensitivity: 3,
222	          scrollSensitivity: 1,
223	        });
224	
225	        // Add FitAddon for responsive sizing
226	        const fit = new FitAddon();
227	        terminal.loadAddon(fit);
228	        fitAddon.current = fit;
229	
230	        // Add WebLinksAddon for clickable links
231	        const webLinks = new WebLinksAddon();
232	        terminal.loadAddon(webLinks);
233	
234	        // **CRITICAL FIX**: Register XDA (Extended Device Attributes) handler
235	        // This makes tmux recognize our terminal and enable clipboard support
236	        terminal.parser.registerCsiHandler(
237	          { prefix: ">", final: "q" }, // CSI > q is XTVERSION / XDA
238	          () => {
239	            // Respond with XTerm identification that tmux recognizes
240	            // tmux looks for "XTerm(" in the response (see tmux tty-keys.c)
241	            // Format: DCS > | XTerm(version) ST
242	            // DCS = \x1bP, ST = \x1b\\
243	            terminal.write("\x1bP>|XTerm(370)\x1b\\");
244	            console.log("[DirectTerminal] Sent XDA response for clipboard support");
245	            return true; // Handled
246	          },
247	        );
248	
249	        // Register OSC 52 handler for clipboard support
250	        // tmux sends OSC 52 with base64-encoded text when copying
251	        terminal.parser.registerOscHandler(52, (data) => {
252	          const parts = data.split(";");
253	          if (parts.length < 2) return false;
254	          const b64 = parts[parts.length - 1];
255	          try {
256	            // Decode base64 → binary string → Uint8Array → UTF-8 text
257	            // atob() alone only handles Latin-1; TextDecoder is needed for UTF-8
258	            const binary = atob(b64);
259	            const bytes = Uint8Array.from(binary, (c) => c.charCodeAt(0));
260	            const text = new TextDecoder().decode(bytes);
261	            navigator.clipboard?.writeText(text).catch(() => {});
262	          } catch {
263	            // Ignore decode errors
264	          }
265	          return true;
266	        });
267	
268	        // Open terminal in DOM
269	        terminal.open(terminalRef.current);
270	        terminalInstance.current = terminal;
271	
272	        // Fit terminal to container
273	        fit.fit();
274	
275	        // ── Preserve selection while terminal receives output ────────
276	        // xterm.js clears the selection on every terminal.write(). We
277	        // buffer incoming data while a selection is active so the
278	        // highlight stays visible for Cmd+C. The buffer is flushed
279	        // when the selection is cleared (click, keypress, etc.).
280	        const writeBuffer: string[] = [];
281	        let selectionActive = false;
282	        let safetyTimer: ReturnType<typeof setTimeout> | null = null;
283	        let bufferBytes = 0;
284	        const MAX_BUFFER_BYTES = 1_048_576; // 1 MB
285	
286	        const flushWriteBuffer = () => {
287	          if (safetyTimer) {
288	            clearTimeout(safetyTimer);
289	            safetyTimer = null;
290	          }
291	          if (writeBuffer.length > 0) {
292	            terminal.write(writeBuffer.join(""));
293	            writeBuffer.length = 0;
294	            bufferBytes = 0;
295	          }
296	        };
297	
298	        const selectionDisposable = terminal.onSelectionChange(() => {
299	          if (terminal.hasSelection()) {
300	            selectionActive = true;
301	            // Safety: flush after 5s to prevent unbounded buffering
302	            if (!safetyTimer) {
303	              safetyTimer = setTimeout(() => {
304	                selectionActive = false;
305	                flushWriteBuffer();
306	              }, 5_000);
307	            }
308	          } else {
309	            selectionActive = false;
310	            flushWriteBuffer();
311	          }
312	        });
313	
314	        // Intercept Cmd+C (Mac) and Ctrl+Shift+C (Linux/Win) for copy.
315	        // Paste (Cmd+V / Ctrl+Shift+V) is handled natively by xterm.js
316	        // via its internal textarea — no custom handler needed.
317	        terminal.attachCustomKeyEventHandler((e: KeyboardEvent) => {
318	          if (e.type !== "keydown") return true;
319	
320	          // Cmd+C / Ctrl+Shift+C — copy selection
321	          const isCopy =
322	            (e.metaKey && !e.ctrlKey && !e.altKey && e.code === "KeyC") ||
323	            (e.ctrlKey && e.shiftKey && e.code === "KeyC");
324	          if (isCopy && terminal.hasSelection()) {
325	            navigator.clipboard?.writeText(terminal.getSelection()).catch(() => {});
326	            // Clear selection so the terminal resumes receiving output
327	            terminal.clearSelection();
328	            return false;
329	          }
330	
331	          return true;
332	        });
333	
334	        // Open terminal via mux
335	        openTerminal(sessionId);
336	
337	        // Subscribe to terminal data via mux
338	        unsubscribe = subscribeTerminal(sessionId, (data) => {
339	          if (selectionActive) {
340	            writeBuffer.push(data);
341	            bufferBytes += data.length;
342	            // Flush if buffer exceeds 1 MB to prevent OOM
343	            if (bufferBytes > MAX_BUFFER_BYTES) {
344	              selectionActive = false;
345	              flushWriteBuffer();
346	            }
347	          } else {
348	            terminal.write(data);
349	          }
350	        });
351	
352	        // Handle window resize
353	        const handleResize = () => {
354	          if (fit) {
355	            fit.fit();
356	            resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
357	          }
358	        };
359	
360	        window.addEventListener("resize", handleResize);
361	
362	        // Terminal input → mux
363	        inputDisposable = terminal.onData((data) => {
364	          writeTerminal(sessionId, data);
365	        });
366	
367	        // Send initial size
368	        resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
369	
370	        // Store cleanup function to be called from useEffect cleanup
371	        cleanup = () => {
372	          selectionDisposable.dispose();
373	          if (safetyTimer) clearTimeout(safetyTimer);
374	          window.removeEventListener("resize", handleResize);
375	          inputDisposable?.dispose();
376	          inputDisposable = null;
377	          unsubscribe?.();
378	          closeTerminal(sessionId);
379	          terminal.dispose();
380	        };
381	      })
382	      .catch((err) => {
383	        console.error("[DirectTerminal] Failed to load xterm.js:", err);
384	        setError("Failed to load terminal");
385	      });
386	
387	    return () => {
388	      mounted = false;
389	      cleanup?.();
390	    };
391	  }, [
392	    appearance,
393	    sessionId,
394	    variant,
395	    resolvedTheme,
396	    terminalThemes,
397	    subscribeTerminal,
398	    writeTerminal,
399	    resizeTerminalMux,
400	    openTerminal,
401	    closeTerminal,
402	  ]);
403	
404	  // Re-send terminal dimensions on every reconnect so the server-side PTY
405	  // matches the client's xterm.js size (new PTYs spawn at 80×24 default).
406	  useEffect(() => {
407	    if (muxStatus !== "connected") return;
408	    const fit = fitAddon.current;
409	    const terminal = terminalInstance.current;
410	    if (!fit || !terminal) return;
411	    fit.fit();
412	    resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
413	  }, [muxStatus, sessionId, resizeTerminalMux]);
414	
415	  // Live theme switching without terminal recreation
416	  useEffect(() => {
417	    const terminal = terminalInstance.current;
418	    if (!terminal) return;
419	    const isDark = appearance === "dark" || resolvedTheme !== "light";
420	    terminal.options.theme = isDark ? terminalThemes.dark : terminalThemes.light;
421	    terminal.options.minimumContrastRatio = isDark ? 1 : 7;
422	  }, [appearance, resolvedTheme, terminalThemes]);
423	
424	  // Re-fit terminal when fullscreen changes
425	  useEffect(() => {
426	    const fit = fitAddon.current;
427	    const terminal = terminalInstance.current;
428	    const container = terminalRef.current;
429	
430	    if (!fit || !terminal || muxStatusRef.current !== "connected" || !container) {
431	      return;
432	    }
433	
434	    let resizeAttempts = 0;
435	    const maxAttempts = 60;
436	    let cancelled = false;
437	    let rafId = 0;
438	    let lastHeight = -1;
439	
440	    const resizeTerminal = () => {
441	      if (cancelled) return;
442	      resizeAttempts++;
443	
444	      // Wait for the container height to stabilise (CSS transition finished)
445	      const currentHeight = container.getBoundingClientRect().height;
446	      const settled = lastHeight >= 0 && Math.abs(currentHeight - lastHeight) < 1;
447	      lastHeight = currentHeight;
448	
449	      if (!settled && resizeAttempts < maxAttempts) {
450	        // Container is still transitioning, try again next frame
451	        rafId = requestAnimationFrame(resizeTerminal);
452	        return;
453	      }
454	
455	      // Container is at target size, now resize terminal
456	      terminal.refresh(0, terminal.rows - 1);
457	      fit.fit();
458	      terminal.refresh(0, terminal.rows - 1);
459	
460	      // Send new size to server via mux
461	      resizeTerminalMux(sessionId, terminal.cols, terminal.rows);
462	    };
463	
464	    // Start resize polling
465	    rafId = requestAnimationFrame(resizeTerminal);
466	
467	    // Also try on transitionend
468	    const handleTransitionEnd = (e: TransitionEvent) => {
469	      if (cancelled) return;
470	      if (e.target === container.parentElement) {
471	        resizeAttempts = 0;
472	        lastHeight = -1;
473	        setTimeout(() => {
474	          if (!cancelled) rafId = requestAnimationFrame(resizeTerminal);
475	        }, 50);
476	      }
477	    };
478	
479	    const parent = container.parentElement;
480	    parent?.addEventListener("transitionend", handleTransitionEnd);
481	
482	    // Backup timers in case RAF polling doesn't work
483	    const timer1 = setTimeout(() => {
484	      if (cancelled) return;
485	      resizeAttempts = 0;
486	      lastHeight = -1;
487	      resizeTerminal();
488	    }, 300);
489	    const timer2 = setTimeout(() => {
490	      if (cancelled) return;
491	      resizeAttempts = 0;
492	      lastHeight = -1;
493	      resizeTerminal();
494	    }, 600);
495	
496	    return () => {
497	      cancelled = true;
498	      cancelAnimationFrame(rafId);
499	      parent?.removeEventListener("transitionend", handleTransitionEnd);
500	      clearTimeout(timer1);
501	      clearTimeout(timer2);
502	    };
503	  }, [fullscreen, sessionId, resizeTerminalMux]);
504	
505	  const accentColor = "var(--color-accent)";
506	
507	  // Local errors (e.g. xterm.js load failure) take priority over mux connection state
508	  const displayStatus = error ? "error" : muxStatus;
509	
510	  const statusDotClass =
511	    displayStatus === "connected"
512	      ? "bg-[var(--color-status-ready)]"
513	      : displayStatus === "error" || displayStatus === "disconnected"
514	        ? "bg-[var(--color-status-error)]"
515	        : "bg-[var(--color-status-attention)] animate-[pulse_1.5s_ease-in-out_infinite]";
516	
517	  const statusText =
518	    displayStatus === "connected"
519	      ? "Connected"
520	      : displayStatus === "error"
521	        ? (error ?? "Error")
522	        : displayStatus === "disconnected"
523	          ? "Disconnected"
524	          : "Connecting…";
525	
526	  const statusTextColor =
527	    displayStatus === "connected"
528	      ? "text-[var(--color-status-ready)]"
529	      : displayStatus === "error" || displayStatus === "disconnected"
530	        ? "text-[var(--color-status-error)]"
531	        : "text-[var(--color-text-tertiary)]";
532	  const isDarkChrome = appearance === "dark" || resolvedTheme !== "light";
533	  const fullscreenButton = (
534	    <button
535	      onClick={() => setFullscreen(!fullscreen)}
536	      className={cn(
537	        "flex items-center gap-1 px-2 py-0.5 text-[11px] text-[var(--color-text-tertiary)] transition-colors hover:bg-[var(--color-bg-subtle)] hover:text-[var(--color-text-primary)]",
538	        !isOpenCodeSession && !chromeless && "ml-auto",
539	      )}
540	      aria-label={fullscreen ? "exit fullscreen" : "fullscreen"}
541	    >
542	      {fullscreen ? (
543	        <>
544	          <svg
545	            className="h-3 w-3"
546	            fill="none"
547	            stroke="currentColor"
548	            strokeWidth="2"
549	            viewBox="0 0 24 24"
550	          >
551	            <path d="M8 3v3a2 2 0 01-2 2H3m18 0h-3a2 2 0 01-2-2V3m0 18v-3a2 2 0 012-2h3M3 16h3a2 2 0 012 2v3" />
552	          </svg>
553	          exit fullscreen
554	        </>
555	      ) : (
556	        <>
557	          <svg
558	            className="h-3 w-3"
559	            fill="none"
560	            stroke="currentColor"
561	            strokeWidth="2"
562	            viewBox="0 0 24 24"
563	          >
564	            <path d="M8 3H5a2 2 0 00-2 2v3m18 0V5a2 2 0 00-2-2h-3m0 18h3a2 2 0 002-2v-3M3 16v3a2 2 0 002 2h3" />
565	          </svg>
566	          fullscreen
567	        </>
568	      )}
569	    </button>
570	  );
571	
572	  return (
573	    <div
574	      className={cn(
575	        "overflow-hidden border border-[var(--color-border-default)]",
576	        fullscreen ? "fixed inset-0 z-50 rounded-none border-0" : "relative",
577	        isDarkChrome ? "bg-[#0a0a0f]" : "bg-[#fafafa]",
578	        chromeless && "border-0",
579	      )}
580	    >
581	      {!chromeless ? (
582	        <div className="flex items-center gap-2 border-b border-[var(--color-border-subtle)] bg-[var(--color-bg-elevated)] px-3 py-2">
583	          <div className={cn("h-2 w-2 shrink-0 rounded-full", statusDotClass)} />
584	          <span className="font-[var(--font-mono)] text-[11px]" style={{ color: accentColor }}>
585	            {sessionId}
586	          </span>
587	          <span
588	            className={cn("text-[10px] font-medium uppercase tracking-[0.06em]", statusTextColor)}
589	          >
590	            {statusText}
591	          </span>
592	          <span
593	            className="px-1.5 py-0.5 text-[9px] font-semibold uppercase tracking-[0.06em]"
594	            style={{
595	              color: accentColor,
596	              background: `color-mix(in srgb, ${accentColor} 12%, transparent)`,
597	            }}
598	          >
599	            XDA
600	          </span>
601	          {isOpenCodeSession ? (
602	            <button
603	              onClick={handleReload}
604	              disabled={reloading || muxStatus !== "connected"}
605	              title="Restart OpenCode session (/exit then resume mapped session)"
606	              aria-label="Restart OpenCode session"
607	              className="ml-auto flex items-center gap-1 px-2 py-0.5 text-[11px] text-[var(--color-text-tertiary)] transition-colors hover:bg-[var(--color-bg-subtle)] hover:text-[var(--color-text-primary)] disabled:cursor-not-allowed disabled:opacity-70"
608	            >
609	              {reloading ? (
610	                <>
611	                  <svg
612	                    className="h-3 w-3 animate-spin"
613	                    fill="none"
614	                    stroke="currentColor"
